   using System;
   using System.Drawing;
   using System.Drawing.Imaging;
   using System.Runtime.InteropServices;
   using System.Windows.Forms;

   public class HmiCapture
   {
       [DllImport("user32.dll")]
       private static extern IntPtr GetForegroundWindow();

       [DllImport("user32.dll")]
       private static extern bool GetWindowRect(IntPtr hWnd, out RECT lpRect);

       [StructLayout(LayoutKind.Sequential)]
       private struct RECT { public int Left; public int Top; public int Right; public int Bottom; }

       public static void CaptureScreen(string outputPath)
       {
           // Capture all screens
           int width = SystemInformation.VirtualScreen.Width;
           int height = SystemInformation.VirtualScreen.Height;
           int x = SystemInformation.VirtualScreen.X;
           int y = SystemInformation.VirtualScreen.Y;

           using (Bitmap bmp = new Bitmap(width, height, PixelFormat.Format32bppArgb))
           {
               using (Graphics g = Graphics.FromImage(bmp))
               {
                   g.CopyFromScreen(x, y, 0, 0, new Size(width, height), CopyPixelOperation.SourceCopy);
               }
               bmp.Save(outputPath, ImageFormat.Png);
           }
       }

       // Optional: Capture specific window (often better for HMIs)
       public static void CaptureWindow(string windowTitle, string outputPath)
       {
           IntPtr hWnd = IntPtr.Zero;
           Process[] processes = Process.GetProcesses();
           foreach (Process p in processes)
           {
               if (p.MainWindowTitle.Contains(windowTitle))
               {
                   hWnd = p.MainWindowHandle;
                   break;
               }
           }

           if (hWnd != IntPtr.Zero)
           {
               RECT rect;
               GetWindowRect(hWnd, out rect);
               int width = rect.Right - rect.Left;
               int height = rect.Bottom - rect.Top;

               using (Bitmap bmp = new Bitmap(width, height, PixelFormat.Format32bppArgb))
               {
                   using (Graphics g = Graphics.FromImage(bmp))
                   {
                       g.CopyFromScreen(rect.Left, rect.Top, 0, 0, new Size(width, height), CopyPixelOperation.SourceCopy);
                   }
                   bmp.Save(outputPath, ImageFormat.Png);
               }
           }
       }
   }
